    if pid == 'funasr':
        asr_ok = True
    else:
        asr_ok = bool(config.get('asr_keys', {}).get(pid, {}).get('key'))
    llm_ok = bool(config.get('llm_keys', {}).get(config['llm_provider'], {}).get('key'))
